INSERT INTO `settings` (`sr_no`,`site_title`,`site_about`,`shutdown`,`payment_gcash_number`,`payment_maya_number`,`payment_gcash_qr`,`payment_maya_qr`,`booking_rules`) VALUES ('1','Travelers Place','Welcome to Travelers Place, your cozy retreat in the heart of Santo Niño, San Felipe, Zambales. We’re more than just a place to stay—we’re your home away from home. With clean rooms, fun amenities, and warm hospitality, we make sure every guest feels','0','09916057372','09075767425','http://127.0.0.1/SE/images/payments/PAYMENT_GCASH_QR_1764570103629.jpg','http://127.0.0.1/SE/images/payments/PAYMENT_MAYA_QR_1764570103219.jpg','50% downpayment is required to confirm your booking.\nThe remaining 50% balance is due upon check-in.\nCheck-in time is 2:00 PM; Check-out time is 12:00 PM (noon).\nCancellations will be refunded 50% of the total amount paid.\nGuests are responsible for any damage to room property during their stay.\nNo smoking inside the rooms. Designated smoking areas are available outside.\nPlease observe quiet hours from 10:00 PM to 7:00 AM.\nA valid government-issued ID is required upon check-in.');
